import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import '../styles/Profile.css';

function Profile() {
  const navigate = useNavigate();
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [userData, setUserData] = useState({
    email: '',
    name: '',
    age: '',
    sex: '',
    smoking: '',
    allergy: ''
  });
  const [originalData, setOriginalData] = useState(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  const toggleSidebar = () => {
    setIsSidebarOpen(!isSidebarOpen);
  };

  useEffect(() => {
    const fetchUserData = async () => {
      const user_id = localStorage.getItem('user_id');
      if (!user_id) {
        navigate('/');
        return;
      }

      try {
        const response = await fetch(`http://localhost:5000/api/user-data/${user_id}`);
        const data = await response.json();

        if (response.ok) {
          const emailRes = await fetch(`http://localhost:5000/api/user-email/${user_id}`);
          const emailData = await emailRes.json();
          if (emailRes.ok) {
            const completeData = {
              ...data,
              email: emailData.email,
              smoking: data.smoking === 1 ? 'yes' : 'no',
              sex: data.sex
            };
            setUserData(completeData);
            setOriginalData(completeData);
          }
        }
      } catch (err) {
        setError('Failed to load user data');
      } finally {
        setIsLoading(false);
      }
    };

    fetchUserData();
  }, [navigate]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setUserData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setSuccess('');
    const user_id = localStorage.getItem('user_id');
    if (!user_id) return;

    try {
      const updateRes = await fetch(`http://localhost:5000/api/update-user-data/${user_id}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          name: userData.name,
          age: userData.age,
          sex: userData.sex,
          smoking: userData.smoking === 'yes' ? 1 : 0,
          allergy: userData.allergy
        })
      });

      if (!updateRes.ok) throw new Error();

      if (userData.email !== originalData.email) {
        const emailRes = await fetch(`http://localhost:5000/api/update-email/${user_id}`, {
          method: 'PUT',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ email: userData.email })
        });
        if (!emailRes.ok) throw new Error();
      }

      setSuccess('Changes saved successfully');
      setOriginalData(userData);
    } catch {
      setError('Failed to save changes');
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('user_id');
    navigate('/');
  };

  const hasChanges = () => {
    if (!originalData) return false;
    return Object.keys(userData).some(key => userData[key] !== originalData[key]);
  };

  if (isLoading) return <div className="profile-container">Loading...</div>;

  return (
    <div className={`profile-container ${isSidebarOpen ? 'sidebar-open' : ''}`}>
      {/* Top Bar */}
      <div className="top-bar">
        <div className="top-center">
          <h1>Asthma Monitoring</h1>
          <p className="welcome-text">Profile Settings</p>
        </div>
        <div className="nav-buttons">
          <button className="dashboard-button" onClick={() => navigate('/dashboard')}>
            Dashboard
          </button>
          <button className="logout-button" onClick={handleLogout}>
            Logout
          </button>
        </div>
      </div>

      {/* Sidebar */}
      <div className={`sidebar ${isSidebarOpen ? 'open' : ''}`}>
        <div className="sidebar-header">
          <h2>Menu</h2>
        </div>
        <nav className="sidebar-nav">
          <button onClick={() => navigate('/dashboard')}>Home</button>
          <button onClick={() => navigate('/recording-indicators')}>Recording Indicators</button>
          <button onClick={() => navigate('/exacerbation-forecast')}>Exacerbation Forecast</button>
          <button onClick={() => navigate('/graphs-of-changes')}>Graphs of Changes</button>
          <button onClick={() => navigate('/medication-diary')}>Medication Diary</button>
        </nav>
      </div>

      {/* Floating Button */}
      <div className="floating-menu-button" onClick={toggleSidebar}>
        <span></span>
        <span></span>
        <span></span>
      </div>

      {/* Content */}
      <div className="profile-content">
        {error && <div className="error-message">{error}</div>}
        {success && <div className="success-message">{success}</div>}

        <form onSubmit={handleSubmit} className="profile-form">
          {/* Fields same as before */}
          {/* Email, Name, Age, Sex, Smoking, Allergy */}
        </form>
      </div>
    </div>
  );
}

export default Profile;
